import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { obtenerProductos, guardarProducto } from '../services/productoService';

// ─── Estilos globales inyectados una sola vez ───────────────────────────────
const STYLES = `
  @import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;600;700&family=Sora:wght@300;400;600;700&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body { background: #0d0f14; }

  .inv-root {
    min-height: 100vh;
    background: #0d0f14;
    color: #e8eaf0;
    font-family: 'Sora', sans-serif;
    padding: 28px 32px;
  }

  /* ── HEADER ── */
  .inv-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 32px;
    gap: 16px;
    flex-wrap: wrap;
  }
  .inv-title { font-size: 26px; font-weight: 700; letter-spacing: -0.5px; }
  .inv-title span { color: #4f9eff; }
  .inv-badge {
    display: inline-flex; align-items: center; gap: 6px;
    font-size: 12px; font-family: 'JetBrains Mono', monospace;
    padding: 4px 12px; border-radius: 20px; font-weight: 600;
    margin-top: 6px;
  }
  .inv-badge.admin { background: rgba(79,158,255,0.15); border: 1px solid rgba(79,158,255,0.4); color: #4f9eff; }
  .inv-badge.vendedor { background: rgba(52,211,153,0.15); border: 1px solid rgba(52,211,153,0.4); color: #34d399; }

  .inv-btn-group { display: flex; gap: 10px; flex-wrap: wrap; align-items: center; }
  .inv-btn {
    display: inline-flex; align-items: center; gap: 7px;
    padding: 10px 18px; border: none; border-radius: 8px;
    font-family: 'Sora', sans-serif; font-size: 13px; font-weight: 600;
    cursor: pointer; transition: all .18s ease; white-space: nowrap;
  }
  .inv-btn:hover { transform: translateY(-1px); filter: brightness(1.12); }
  .inv-btn.purple { background: #6c47ff; color: #fff; }
  .inv-btn.orange { background: #f59e0b; color: #000; }
  .inv-btn.green  { background: #22c55e; color: #000; }
  .inv-btn.red    { background: #ef4444; color: #fff; }
  .inv-btn.blue   { background: #4f9eff; color: #000; }
  .inv-btn.teal   { background: #14b8a6; color: #000; }

  /* ── TABS ── */
  .inv-tabs { display: flex; gap: 4px; margin-bottom: 24px; border-bottom: 1px solid #1e2230; padding-bottom: 0; }
  .inv-tab {
    padding: 10px 22px; border: none; background: transparent;
    color: #6b7280; font-family: 'Sora', sans-serif; font-size: 14px; font-weight: 600;
    cursor: pointer; border-bottom: 2px solid transparent; margin-bottom: -1px;
    transition: all .15s;
  }
  .inv-tab.active { color: #4f9eff; border-bottom-color: #4f9eff; }
  .inv-tab:hover:not(.active) { color: #9ca3af; }

  /* ── STATS BAR ── */
  .inv-stats { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 14px; margin-bottom: 28px; }
  .inv-stat-card {
    background: #131720; border: 1px solid #1e2230; border-radius: 12px;
    padding: 16px 20px;
  }
  .inv-stat-label { font-size: 11px; color: #6b7280; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 6px; font-family: 'JetBrains Mono', monospace; }
  .inv-stat-value { font-size: 22px; font-weight: 700; font-family: 'JetBrains Mono', monospace; }
  .inv-stat-value.blue  { color: #4f9eff; }
  .inv-stat-value.red   { color: #f87171; }
  .inv-stat-value.green { color: #34d399; }
  .inv-stat-value.amber { color: #fbbf24; }

  /* ── SEARCH ── */
  .inv-search-wrap { position: relative; margin-bottom: 20px; }
  .inv-search {
    width: 100%; padding: 13px 16px 13px 44px;
    background: #131720; border: 1px solid #1e2230; border-radius: 10px;
    color: #e8eaf0; font-family: 'Sora', sans-serif; font-size: 14px;
    transition: border-color .2s;
  }
  .inv-search:focus { outline: none; border-color: #4f9eff; }
  .inv-search::placeholder { color: #4b5563; }
  .inv-search-icon { position: absolute; left: 14px; top: 50%; transform: translateY(-50%); color: #4b5563; font-size: 18px; pointer-events: none; }

  /* ── FORM ── */
  .inv-form {
    background: #131720; border: 1px solid #1e2230; border-radius: 14px;
    padding: 22px; margin-bottom: 28px;
  }
  .inv-form.editing { border-color: #f59e0b44; background: #1a1508; }
  .inv-form-title { font-size: 15px; font-weight: 700; margin-bottom: 16px; display: flex; align-items: center; gap: 8px; }
  .inv-form-grid { display: flex; flex-wrap: wrap; gap: 12px; }
  .inv-input {
    padding: 10px 14px; background: #0d0f14; border: 1px solid #1e2230;
    border-radius: 8px; color: #e8eaf0; font-family: 'Sora', sans-serif; font-size: 13px;
    transition: border-color .18s;
  }
  .inv-input:focus { outline: none; border-color: #4f9eff; }
  .inv-input::placeholder { color: #4b5563; }
  .inv-input.flex1 { flex: 1; min-width: 140px; }

  /* ── TABLE ── */
  .inv-table-wrap { overflow-x: auto; border-radius: 14px; border: 1px solid #1e2230; }
  .inv-table { width: 100%; border-collapse: collapse; }
  .inv-table thead tr { background: #131720; }
  .inv-table th {
    padding: 13px 16px; text-align: left;
    font-size: 11px; font-family: 'JetBrains Mono', monospace;
    text-transform: uppercase; letter-spacing: 1px; color: #6b7280;
    border-bottom: 1px solid #1e2230; white-space: nowrap;
  }
  .inv-table td { padding: 12px 16px; border-bottom: 1px solid #0f1117; font-size: 13px; }
  .inv-table tbody tr:hover { background: #131720; }
  .inv-table tbody tr:last-child td { border-bottom: none; }

  .stock-badge {
    display: inline-flex; align-items: center; gap: 5px;
    padding: 3px 10px; border-radius: 20px; font-size: 12px; font-weight: 600; font-family: 'JetBrains Mono', monospace;
  }
  .stock-badge.ok { background: rgba(34,197,94,0.12); color: #22c55e; border: 1px solid rgba(34,197,94,0.3); }
  .stock-badge.low { background: rgba(251,191,36,0.12); color: #fbbf24; border: 1px solid rgba(251,191,36,0.3); }
  .stock-badge.critical { background: rgba(239,68,68,0.12); color: #ef4444; border: 1px solid rgba(239,68,68,0.3); }

  .mono { font-family: 'JetBrains Mono', monospace; }

  /* ── STOCK EDIT INLINE ── */
  .stock-edit-wrap { display: flex; align-items: center; gap: 8px; }
  .stock-inline-input {
    width: 70px; padding: 5px 9px;
    background: #0d0f14; border: 1px solid #4f9eff;
    border-radius: 6px; color: #4f9eff; font-family: 'JetBrains Mono', monospace;
    font-size: 13px; font-weight: 600;
  }
  .stock-inline-input:focus { outline: none; box-shadow: 0 0 0 2px rgba(79,158,255,.25); }
  .icon-btn {
    width: 28px; height: 28px; border: none; border-radius: 6px;
    cursor: pointer; display: flex; align-items: center; justify-content: center;
    font-size: 14px; transition: all .15s;
  }
  .icon-btn.save { background: rgba(34,197,94,.18); color: #22c55e; }
  .icon-btn.save:hover { background: rgba(34,197,94,.3); }
  .icon-btn.cancel { background: rgba(239,68,68,.14); color: #ef4444; }
  .icon-btn.cancel:hover { background: rgba(239,68,68,.25); }
  .icon-btn.edit { background: rgba(79,158,255,.14); color: #4f9eff; }
  .icon-btn.edit:hover { background: rgba(79,158,255,.25); }

  /* ── LIMIT BANNER ── */
  .limit-banner {
    display: flex; align-items: center; gap: 10px;
    background: rgba(251,191,36,0.07); border: 1px solid rgba(251,191,36,0.25);
    border-radius: 10px; padding: 12px 18px; margin-bottom: 20px; font-size: 13px;
  }

  /* ── COSTOS PANEL ── */
  .costos-section { margin-top: 4px; }
  .costos-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; }
  .costos-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 14px; margin-bottom: 28px; }
  .costo-card {
    background: #131720; border: 1px solid #1e2230; border-radius: 12px; padding: 20px;
    position: relative; overflow: hidden;
  }
  .costo-card::before {
    content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px;
  }
  .costo-card.total::before { background: linear-gradient(90deg, #4f9eff, #818cf8); }
  .costo-card.invertido::before { background: linear-gradient(90deg, #f87171, #fb923c); }
  .costo-card.ganancia::before { background: linear-gradient(90deg, #34d399, #22c55e); }
  .costo-card.margen::before { background: linear-gradient(90deg, #fbbf24, #f59e0b); }
  .costo-icon { font-size: 28px; margin-bottom: 10px; }
  .costo-label { font-size: 11px; color: #6b7280; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 4px; font-family: 'JetBrains Mono', monospace; }
  .costo-value { font-size: 28px; font-weight: 700; font-family: 'JetBrains Mono', monospace; }

  /* ── TABLA COSTOS ── */
  .costo-table-title { font-size: 14px; font-weight: 700; margin-bottom: 14px; color: #9ca3af; text-transform: uppercase; letter-spacing: 1px; }
  .profit-pill {
    display: inline-flex; padding: 2px 8px; border-radius: 20px;
    font-size: 11px; font-weight: 700; font-family: 'JetBrains Mono', monospace;
  }
  .profit-pill.pos { background: rgba(34,197,94,.12); color: #22c55e; }
  .profit-pill.neg { background: rgba(239,68,68,.12); color: #ef4444; }

  /* ── MODAL LIMITE ── */
  .modal-overlay {
    position: fixed; inset: 0; background: rgba(0,0,0,.7); z-index: 1000;
    display: flex; align-items: center; justify-content: center;
  }
  .modal-box {
    background: #131720; border: 1px solid #1e2230; border-radius: 16px;
    padding: 28px; width: 360px; max-width: 90vw;
  }
  .modal-title { font-size: 17px; font-weight: 700; margin-bottom: 18px; }
  .modal-label { font-size: 12px; color: #9ca3af; margin-bottom: 6px; font-family: 'JetBrains Mono', monospace; text-transform: uppercase; letter-spacing: 1px; }
  .modal-actions { display: flex; gap: 10px; margin-top: 20px; justify-content: flex-end; }
`;

// ─── Helpers ────────────────────────────────────────────────────────────────
const stockStatus = (stock, limit) => {
  if (stock === 0) return 'critical';
  if (stock <= limit) return 'low';
  return 'ok';
};
const stockLabel = { ok: '✅', low: '⚠️', critical: '🔴' };

// ─── Componente principal ────────────────────────────────────────────────────
const Inventario = () => {
  const navigate = useNavigate();

  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [editandoId, setEditandoId] = useState(null);
  const [nuevoProd, setNuevoProd] = useState({ codigo: '', nombre: '', stock: 0, precioCompra: 0, precioVenta: 0, categoria: 'Fundas' });

  // Stock inline edit
  const [editandoStockId, setEditandoStockId] = useState(null);
  const [nuevoStock, setNuevoStock] = useState('');

  // Límite de stock bajo (configurable)
  const [limiteStock, setLimiteStock] = useState(() => parseInt(localStorage.getItem('limiteStock') || '5'));
  const [modalLimite, setModalLimite] = useState(false);
  const [limiteTemp, setLimiteTemp] = useState('');

  // Tabs
  const [tab, setTab] = useState('inventario'); // 'inventario' | 'costos'

  const matricula = localStorage.getItem('usuarioLogueado') || 'desconocido';
  const rol = localStorage.getItem('rolUsuario') || 'VENDEDOR';
  const esAdmin = rol === 'ADMIN';

  useEffect(() => {
    if (!localStorage.getItem('usuarioLogueado')) {
      alert('⚠️ Acceso denegado. Por favor, inicia sesión.');
      navigate('/');
    } else {
      cargarProductos();
    }
  }, [navigate]);

  const cargarProductos = async () => {
    const data = await obtenerProductos();
    setProductos(data);
  };

  const productosFiltrados = productos.filter(p =>
    p.nombre.toLowerCase().includes(busqueda.toLowerCase()) ||
    p.codigo.toLowerCase().includes(busqueda.toLowerCase())
  );

  // ── Guardar producto (form completo) ──
  const handleGuardar = async (e) => {
    e.preventDefault();
    if (!esAdmin) return;
    await guardarProducto({ ...nuevoProd, id: editandoId, registradoPorMatricula: matricula });
    alert(editandoId ? '✅ Producto actualizado' : '✅ Producto guardado');
    setNuevoProd({ codigo: '', nombre: '', stock: 0, precioCompra: 0, precioVenta: 0, categoria: 'Fundas' });
    setEditandoId(null);
    cargarProductos();
  };

  const prepararEdicion = (p) => {
    setEditandoId(p.id);
    setNuevoProd({ codigo: p.codigo, nombre: p.nombre, stock: p.stock, precioCompra: p.precioCompra, precioVenta: p.precioVenta, categoria: p.categoria });
  };

  // ── Edición inline de stock ──
  const iniciarEditStock = (p) => {
    setEditandoStockId(p.id);
    setNuevoStock(String(p.stock));
  };

  const guardarStockInline = async (p) => {
    const stockNum = parseInt(nuevoStock);
    if (isNaN(stockNum) || stockNum < 0) { alert('Stock inválido'); return; }
    await guardarProducto({ ...p, stock: stockNum, registradoPorMatricula: matricula });
    setEditandoStockId(null);
    cargarProductos();
  };

  // ── Guardar límite ──
  const guardarLimite = () => {
    const val = parseInt(limiteTemp);
    if (isNaN(val) || val < 0) { alert('Valor inválido'); return; }
    setLimiteStock(val);
    localStorage.setItem('limiteStock', val);
    setModalLimite(false);
  };

  // ── Estadísticas ──
  const totalProductos = productos.length;
  const totalUnidades = productos.reduce((s, p) => s + p.stock, 0);
  const totalInvertido = productos.reduce((s, p) => s + p.precioCompra * p.stock, 0);
  const totalValorVenta = productos.reduce((s, p) => s + p.precioVenta * p.stock, 0);
  const gananciaPotencial = totalValorVenta - totalInvertido;
  const margen = totalInvertido > 0 ? ((gananciaPotencial / totalInvertido) * 100).toFixed(1) : 0;
  const bajoStock = productos.filter(p => p.stock <= limiteStock).length;

  const handleLogout = () => {
    localStorage.removeItem('usuarioLogueado');
    localStorage.removeItem('rolUsuario');
    navigate('/');
  };

  return (
    <>
      <style>{STYLES}</style>
      <div className="inv-root">

        {/* ── HEADER ── */}
        <div className="inv-header">
          <div>
            <div className="inv-title">📦 <span>Isla</span> Tecnológica</div>
            <span className={`inv-badge ${esAdmin ? 'admin' : 'vendedor'}`}>
              {esAdmin ? '🔑 Admin' : '👤 Vendedor'}: {matricula}
            </span>
          </div>
          <div className="inv-btn-group">
            {esAdmin && <>
              <button className="inv-btn purple" onClick={() => navigate('/reportes')}>📈 Ganancias</button>
              <button className="inv-btn orange" onClick={() => navigate('/usuarios')}>👥 Usuarios</button>
              <button className="inv-btn teal" onClick={() => { setLimiteTemp(String(limiteStock)); setModalLimite(true); }}>⚙️ Límite Stock</button>
            </>}
            <button className="inv-btn green" onClick={() => navigate('/ventas')}>🛒 Ventas</button>
            <button className="inv-btn red" onClick={handleLogout}>Cerrar Sesión</button>
          </div>
        </div>

        {/* ── STATS ── */}
        {esAdmin && (
          <div className="inv-stats">
            <div className="inv-stat-card">
              <div className="inv-stat-label">Productos</div>
              <div className="inv-stat-value blue">{totalProductos}</div>
            </div>
            <div className="inv-stat-card">
              <div className="inv-stat-label">Unidades Totales</div>
              <div className="inv-stat-value blue">{totalUnidades}</div>
            </div>
            <div className="inv-stat-card">
              <div className="inv-stat-label">Capital Invertido</div>
              <div className="inv-stat-value red">${totalInvertido.toFixed(2)}</div>
            </div>
            <div className="inv-stat-card">
              <div className="inv-stat-label">Bajo Stock (≤{limiteStock})</div>
              <div className="inv-stat-value amber">{bajoStock} prods</div>
            </div>
          </div>
        )}

        {/* ── TABS ── */}
        {esAdmin && (
          <div className="inv-tabs">
            <button className={`inv-tab ${tab === 'inventario' ? 'active' : ''}`} onClick={() => setTab('inventario')}>📦 Inventario</button>
            <button className={`inv-tab ${tab === 'costos' ? 'active' : ''}`} onClick={() => setTab('costos')}>💰 Costos & Capital</button>
          </div>
        )}

        {/* ══════════════════════════════════════════
            TAB: INVENTARIO
        ══════════════════════════════════════════ */}
        {tab === 'inventario' && (
          <>
            {/* Banner límite */}
            {esAdmin && bajoStock > 0 && (
              <div className="limit-banner">
                <span style={{ fontSize: 20 }}>⚠️</span>
                <span><strong>{bajoStock} producto(s)</strong> con stock igual o menor al límite configurado ({limiteStock} unidades).</span>
                <button className="inv-btn orange" style={{ marginLeft: 'auto', padding: '6px 14px', fontSize: 12 }} onClick={() => { setLimiteTemp(String(limiteStock)); setModalLimite(true); }}>
                  Cambiar límite
                </button>
              </div>
            )}

            {/* Form admin */}
            {esAdmin && (
              <div className={`inv-form ${editandoId ? 'editing' : ''}`}>
                <div className="inv-form-title">
                  {editandoId ? '✏️ Editando Producto' : '➕ Agregar Nuevo Producto'}
                </div>
                <form onSubmit={handleGuardar}>
                  <div className="inv-form-grid">
                    <input className="inv-input" placeholder="Código" value={nuevoProd.codigo} onChange={e => setNuevoProd({ ...nuevoProd, codigo: e.target.value })} required />
                    <input className="inv-input flex1" placeholder="Nombre del producto" value={nuevoProd.nombre} onChange={e => setNuevoProd({ ...nuevoProd, nombre: e.target.value })} required />
                    <input className="inv-input" style={{ width: 90 }} type="number" placeholder="Stock" value={nuevoProd.stock} onChange={e => setNuevoProd({ ...nuevoProd, stock: parseInt(e.target.value) })} required />
                    <input className="inv-input" style={{ width: 130 }} type="number" step="0.01" placeholder="Costo compra $" value={nuevoProd.precioCompra} onChange={e => setNuevoProd({ ...nuevoProd, precioCompra: parseFloat(e.target.value) })} required />
                    <input className="inv-input" style={{ width: 130 }} type="number" step="0.01" placeholder="Precio venta $" value={nuevoProd.precioVenta} onChange={e => setNuevoProd({ ...nuevoProd, precioVenta: parseFloat(e.target.value) })} required />
                  </div>
                  <div style={{ display: 'flex', gap: 10, marginTop: 16 }}>
                    <button type="submit" className={`inv-btn ${editandoId ? 'orange' : 'green'}`}>
                      {editandoId ? 'Actualizar' : 'Guardar Producto'}
                    </button>
                    {editandoId && (
                      <button type="button" className="inv-btn" style={{ background: '#1e2230', color: '#9ca3af' }}
                        onClick={() => { setEditandoId(null); setNuevoProd({ codigo: '', nombre: '', stock: 0, precioCompra: 0, precioVenta: 0, categoria: 'Fundas' }); }}>
                        Cancelar
                      </button>
                    )}
                  </div>
                </form>
              </div>
            )}

            {/* Buscador */}
            <div className="inv-search-wrap">
              <span className="inv-search-icon">🔍</span>
              <input className="inv-search" type="text" placeholder="Buscar por nombre o código..." value={busqueda} onChange={e => setBusqueda(e.target.value)} />
            </div>

            {/* Tabla */}
            <div className="inv-table-wrap">
              <table className="inv-table">
                <thead>
                  <tr>
                    <th>Código</th>
                    <th>Nombre</th>
                    <th>Stock</th>
                    {esAdmin && <th>Costo Unit.</th>}
                    <th>Precio Venta</th>
                    {esAdmin && <th>Ganancia Unit.</th>}
                    {esAdmin && <th>Valor en Stock</th>}
                    {esAdmin && <th>Acciones</th>}
                  </tr>
                </thead>
                <tbody>
                  {productosFiltrados.map(p => {
                    const status = stockStatus(p.stock, limiteStock);
                    const isEditingStock = editandoStockId === p.id;
                    return (
                      <tr key={p.id}>
                        <td><span className="mono" style={{ color: '#6b7280' }}>{p.codigo}</span></td>
                        <td style={{ fontWeight: 500 }}>{p.nombre}</td>
                        <td>
                          {isEditingStock ? (
                            <div className="stock-edit-wrap">
                              <input
                                className="stock-inline-input"
                                type="number"
                                min="0"
                                value={nuevoStock}
                                onChange={e => setNuevoStock(e.target.value)}
                                autoFocus
                                onKeyDown={e => { if (e.key === 'Enter') guardarStockInline(p); if (e.key === 'Escape') setEditandoStockId(null); }}
                              />
                              <button className="icon-btn save" onClick={() => guardarStockInline(p)} title="Guardar">✓</button>
                              <button className="icon-btn cancel" onClick={() => setEditandoStockId(null)} title="Cancelar">✕</button>
                            </div>
                          ) : (
                            <div className="stock-edit-wrap">
                              <span className={`stock-badge ${status}`}>
                                {stockLabel[status]} {p.stock}
                              </span>
                              {esAdmin && (
                                <button className="icon-btn edit" onClick={() => iniciarEditStock(p)} title="Editar stock">✎</button>
                              )}
                            </div>
                          )}
                        </td>
                        {esAdmin && <td className="mono" style={{ color: '#f87171' }}>${p.precioCompra.toFixed(2)}</td>}
                        <td className="mono" style={{ color: '#e8eaf0' }}>${p.precioVenta.toFixed(2)}</td>
                        {esAdmin && (
                          <td className="mono">
                            <span className="profit-pill pos">+${(p.precioVenta - p.precioCompra).toFixed(2)}</span>
                          </td>
                        )}
                        {esAdmin && (
                          <td className="mono" style={{ color: '#4f9eff' }}>${(p.precioCompra * p.stock).toFixed(2)}</td>
                        )}
                        {esAdmin && (
                          <td>
                            <button className="inv-btn blue" style={{ padding: '5px 12px', fontSize: 12 }} onClick={() => prepararEdicion(p)}>Editar</button>
                          </td>
                        )}
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </>
        )}

        {/* ══════════════════════════════════════════
            TAB: COSTOS & CAPITAL
        ══════════════════════════════════════════ */}
        {tab === 'costos' && esAdmin && (
          <div className="costos-section">

            {/* Cards resumen */}
            <div className="costos-grid">
              <div className="costo-card total">
                <div className="costo-icon">📦</div>
                <div className="costo-label">Total Productos</div>
                <div className="costo-value" style={{ color: '#4f9eff' }}>{totalProductos}</div>
                <div style={{ fontSize: 12, color: '#6b7280', marginTop: 4 }}>{totalUnidades} unidades en stock</div>
              </div>
              <div className="costo-card invertido">
                <div className="costo-icon">💸</div>
                <div className="costo-label">Capital Invertido</div>
                <div className="costo-value" style={{ color: '#f87171' }}>${totalInvertido.toFixed(2)}</div>
                <div style={{ fontSize: 12, color: '#6b7280', marginTop: 4 }}>Lo que costó el inventario actual</div>
              </div>
              <div className="costo-card margen">
                <div className="costo-icon">⚠️</div>
                <div className="costo-label">Productos Bajo Stock</div>
                <div className="costo-value" style={{ color: '#fbbf24' }}>{bajoStock}</div>
                <div style={{ fontSize: 12, color: '#6b7280', marginTop: 4 }}>Con ≤{limiteStock} unidades en stock</div>
              </div>
            </div>

            {/* Tabla detalle de costos por producto */}
            <div className="costo-table-title">📋 Desglose de Costos por Producto</div>
            <div className="inv-table-wrap">
              <table className="inv-table">
                <thead>
                  <tr>
                    <th>Código</th>
                    <th>Producto</th>
                    <th>Stock</th>
                    <th>Costo Unit.</th>
                    <th>Capital en Stock</th>
                    <th>Precio Venta</th>
                  </tr>
                </thead>
                <tbody>
                  {[...productos]
                    .sort((a, b) => (b.precioCompra * b.stock) - (a.precioCompra * a.stock))
                    .map(p => {
                      const capitalStock = p.precioCompra * p.stock;
                      return (
                        <tr key={p.id}>
                          <td><span className="mono" style={{ color: '#6b7280' }}>{p.codigo}</span></td>
                          <td style={{ fontWeight: 500 }}>{p.nombre}</td>
                          <td><span className={`stock-badge ${stockStatus(p.stock, limiteStock)}`}>{p.stock}</span></td>
                          <td className="mono" style={{ color: '#f87171' }}>${p.precioCompra.toFixed(2)}</td>
                          <td className="mono" style={{ color: '#f87171', fontWeight: 600 }}>${capitalStock.toFixed(2)}</td>
                          <td className="mono">${p.precioVenta.toFixed(2)}</td>
                        </tr>
                      );
                    })}
                </tbody>
                {/* Footer totales */}
                <tfoot>
                  <tr style={{ background: '#0d0f14', borderTop: '2px solid #1e2230' }}>
                    <td colSpan={4} style={{ padding: '14px 16px', fontWeight: 700, fontSize: 13 }}>TOTAL INVERTIDO</td>
                    <td className="mono" style={{ color: '#f87171', fontWeight: 700, padding: '14px 16px' }}>${totalInvertido.toFixed(2)}</td>
                    <td></td>
                  </tr>
                </tfoot>
              </table>
            </div>
          </div>
        )}

        {/* ── MODAL: Configurar límite de stock ── */}
        {modalLimite && (
          <div className="modal-overlay" onClick={() => setModalLimite(false)}>
            <div className="modal-box" onClick={e => e.stopPropagation()}>
              <div className="modal-title">⚙️ Configurar Límite de Stock Bajo</div>
              <p style={{ fontSize: 13, color: '#9ca3af', marginBottom: 18, lineHeight: 1.6 }}>
                Los productos con stock igual o menor a este número aparecerán marcados como <strong style={{ color: '#fbbf24' }}>⚠️ bajo stock</strong> o <strong style={{ color: '#ef4444' }}>🔴 crítico</strong>.
              </p>
              <div className="modal-label">Límite mínimo de unidades</div>
              <input
                className="inv-input"
                style={{ width: '100%' }}
                type="number"
                min="0"
                value={limiteTemp}
                onChange={e => setLimiteTemp(e.target.value)}
                placeholder={`Actual: ${limiteStock}`}
                autoFocus
              />
              <div style={{ fontSize: 12, color: '#6b7280', marginTop: 8 }}>
                💡 Ejemplo: 5 → productos con ≤5 unidades se marcan como bajo stock.
              </div>
              <div className="modal-actions">
                <button className="inv-btn" style={{ background: '#1e2230', color: '#9ca3af' }} onClick={() => setModalLimite(false)}>Cancelar</button>
                <button className="inv-btn green" onClick={guardarLimite}>Guardar Límite</button>
              </div>
            </div>
          </div>
        )}

      </div>
    </>
  );
};

export default Inventario;
